const DEEPSEEK_BASE = "https://api.deepseek.com/v1";
const MODEL = "deepseek-v4-flash";

export interface AiCallOptions {
  messages: { role: "system" | "user" | "assistant"; content: string }[];
  temperature?: number;
  timeout?: number;
}

export async function callDeepSeek<T = unknown>(
  options: AiCallOptions,
): Promise<T> {
  const { messages, temperature = 0.3, timeout = 5000 } = options;

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeout);

  try {
    const res = await fetch(`${DEEPSEEK_BASE}/chat/completions`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${process.env.AI_API_KEY}`,
      },
      body: JSON.stringify({
        model: MODEL,
        messages,
        temperature,
        response_format: { type: "json_object" },
      }),
      signal: controller.signal,
    });

    if (!res.ok) {
      throw new Error(`DeepSeek API error: ${res.status}`);
    }

    const data = (await res.json()) as {
      choices: { message: { content: string } }[];
    };
    const content = data.choices?.[0]?.message?.content;
    if (!content) throw new Error("Empty response from DeepSeek");

    return JSON.parse(content) as T;
  } catch (e) {
    if (e instanceof DOMException && e.name === "AbortError") {
      throw new Error("DeepSeek API timeout");
    }
    throw e;
  } finally {
    clearTimeout(timer);
  }
}

export interface TriageResult {
  category: "hardware" | "software" | "user_error";
  severity: "high" | "medium" | "low";
  needRepair: boolean;
  reason: string;
  selfHelp: string | null;
}

export function enforceTriageRules(result: TriageResult): TriageResult {
  // Hard rule: severity=high forces needRepair = true
  if (result.severity === "high") {
    result.needRepair = true;
  }

  // Hard rule: selfHelp must be consistent with needRepair
  if (result.needRepair) {
    result.selfHelp = null;
  } else if (!result.selfHelp) {
    result.selfHelp = "请尝试重启设备，如问题持续请联系IT支持。";
  }

  return result;
}

import { SignJWT, jwtVerify } from "jose";

const CONFIRMATION_SECRET = new TextEncoder().encode(
  process.env.AUTH_SECRET + ":confirmation",
);

export interface ConfirmationPayload {
  userId: string;
  action: "create_repair" | "create_apply";
  params: Record<string, unknown>;
  exp: number;
}

const usedTokens = new Set<string>();

export async function generateConfirmationToken(
  payload: Omit<ConfirmationPayload, "exp">,
): Promise<string> {
  const exp = Math.floor(Date.now() / 1000) + 300;
  const token = await new SignJWT({ ...payload, exp })
    .setProtectedHeader({ alg: "HS256" })
    .sign(CONFIRMATION_SECRET);
  return token;
}

export async function verifyConfirmationToken(
  token: string,
  userId: string,
): Promise<ConfirmationPayload | null> {
  try {
    const { payload } = await jwtVerify(token, CONFIRMATION_SECRET, {
      algorithms: ["HS256"],
    });

    if (payload.userId !== userId) return null;

    // One-time use: check blacklist and mark used
    if (usedTokens.has(token)) return null;
    usedTokens.add(token);

    return payload as unknown as ConfirmationPayload;
  } catch {
    return null;
  }
}

export async function withAiFallback<T>(
  fn: () => Promise<T>,
  fallbackMessage: string,
): Promise<{ ok: true; data: T } | { ok: false; fallback: string }> {
  try {
    const data = await fn();
    return { ok: true, data };
  } catch (error) {
    console.error("[AI Fallback]", error);
    return { ok: false, fallback: fallbackMessage };
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, requireOneOf, AuthError } from "@/lib/auth";
import { callDeepSeek } from "@/lib/ai/client";
import { withAiFallback } from "@/lib/ai/with-fallback";

interface RecommendItem {
  modelId: string;
  score: number;
  reason: string;
}

interface RecommendResult {
  recommendations: RecommendItem[];
  topPick: string | null;
}

const SYSTEM_PROMPT = `# 角色
你是一个IT资产管理系统的设备推荐助手，负责根据员工的需求描述，推荐最合适的办公设备型号。

# 输入
你将收到：
1. 用户的需求描述（自然语言）
2. 所有可选的设备型号列表（JSON数组），每个型号包含字段：
   - modelId: 型号编码
   - category: 设备分类（LAPTOP/MONITOR/KEYBOARD/MOUSE/HEADPHONE/OTHER）
   - brandName: 品牌
   - modelName: 型号名称
   - specs: 规格参数（JSON对象，不同分类键不同）
   - stock: 当前可用库存数
   - status: 型号状态（ACTIVE或DISCONTINUED）

# 任务
从型号列表中筛选出最适合用户需求的型号，按匹配度从高到低排序推荐。

# 约束
1. 必须忽略 status 为 "DISCONTINUED" 的型号
2. 如果某个型号的 stock 为 0，推荐理由中必须明确标注"暂无库存"
3. 推荐理由必须具体说明该型号的哪些规格/特性匹配了用户的哪些需求
4. score 字段为 0-100 的整数，表示匹配程度
5. topPick 必须在 recommendations 列表中，且 score 应最高
6. 如果没有任何型号匹配，recommendations 返回空数组，topPick 返回 null

# 输出格式
返回严格的 JSON 对象：
{
  "recommendations": [
    {
      "modelId": "型号编码",
      "score": 95,
      "reason": "推荐理由。若库存为0则追加「暂无库存」"
    }
  ],
  "topPick": "最优型号编码 或 null"
}`;

export async function POST(request: NextRequest) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "EMPLOYEE", "MANAGER");

    const body = (await request.json()) as { requirement?: string };
    if (!body.requirement || typeof body.requirement !== "string") {
      return Response.json({ error: "requirement is required" }, { status: 400 });
    }

    const activeModels = await prisma.assetModel.findMany({
      where: { status: "ACTIVE" },
      include: {
        _count: {
          select: { instances: { where: { status: "IN_STOCK" } } },
        },
      },
    });

    const modelListJson = JSON.stringify(
      activeModels.map((m) => ({
        modelId: m.id,
        category: m.category,
        brandName: m.brandName,
        modelName: m.modelName,
        specs: m.specs,
        stock: m._count.instances,
        status: m.status,
      })),
    );

    const userPrompt = `用户的设备需求：
${body.requirement}

当前可用设备型号列表：
${modelListJson}

请根据用户需求推荐最合适的设备型号。`;

    const result = await withAiFallback(
      () =>
        callDeepSeek<RecommendResult>({
          messages: [
            { role: "system", content: SYSTEM_PROMPT },
            { role: "user", content: userPrompt },
          ],
        }),
      "推荐服务暂时不可用，请稍后重试或浏览全部可用型号自行选择。",
    );

    if (!result.ok) {
      return Response.json(
        { recommendations: [], topPick: null, fallback: result.fallback },
        { status: 200 },
      );
    }

    return Response.json(result.data, { status: 200 });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { verifyAuth, requireOneOf, AuthError } from "@/lib/auth";
import { callDeepSeek } from "@/lib/ai/client";
import { enforceTriageRules, TriageResult } from "@/lib/ai/triage";
import { withAiFallback } from "@/lib/ai/with-fallback";

const SYSTEM_PROMPT = `# 角色
你是一个IT故障诊断助手，负责分析员工的故障描述，判断故障类别、严重程度和是否需要报修。

# 分类规则

## 故障类别 (category)
- "hardware"：硬件物理故障（屏幕损坏、键盘失灵、无法开机、蓝屏、异响、电池鼓包、接口损坏、进液等）
- "software"：软件/系统问题（卡顿、软件报错、驱动问题、网络配置、权限问题、病毒等）
- "user_error"：用户操作问题（不会使用、设置错误、误操作等）

## 严重程度 (severity)
- "high"：严重影响工作，无法正常使用设备
- "medium"：影响部分工作但可勉强使用
- "low"：轻微问题，不影响正常工作

## 是否需要报修 (needRepair)
- "hardware" 通常 → needRepair = true
- "software" 优先自助 → needRepair = false
- "user_error" → needRepair = false

## 自助建议 (selfHelp)
- needRepair = false 时，selfHelp 必须提供具体可操作的自助步骤（中文，2-4步）
- needRepair = true 时，selfHelp 返回 null

# 输出格式
返回严格的 JSON 对象：
{
  "category": "hardware" | "software" | "user_error",
  "severity": "high" | "medium" | "low",
  "needRepair": true | false,
  "reason": "诊断理由（20-50字）",
  "selfHelp": "自助建议步骤 或 null"
}`;

export async function POST(request: NextRequest) {
  try {
    const user = await verifyAuth(request);
    requireOneOf(user, "EMPLOYEE", "MANAGER");

    const body = (await request.json()) as { description?: string };
    if (!body.description || typeof body.description !== "string") {
      return Response.json({ error: "description is required" }, { status: 400 });
    }

    const userPrompt = `请分析以下故障描述：
${body.description}

请根据规则进行诊断分类。`;

    const result = await withAiFallback(
      () =>
        callDeepSeek<TriageResult>({
          messages: [
            { role: "system", content: SYSTEM_PROMPT },
            { role: "user", content: userPrompt },
          ],
        }),
      "故障诊断暂时不可用，你的报修工单已提交，IT 管理员将尽快处理。",
    );

    if (!result.ok) {
      return Response.json(
        {
          triage: null,
          fallback: result.fallback,
        },
        { status: 200 },
      );
    }

    // Apply hard rules after AI response
    const triage = enforceTriageRules(result.data);

    return Response.json({ triage }, { status: 200 });
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { verifyAuth, AuthError } from "@/lib/auth";
import { callDeepSeek } from "@/lib/ai/client";
import { withAiFallback } from "@/lib/ai/with-fallback";
import { generateConfirmationToken } from "@/lib/ai/confirmation-token";

interface ChatHistoryItem {
  role: "user" | "assistant";
  content: string;
}

interface ChatRequest {
  message: string;
  history: ChatHistoryItem[];
}

interface PendingAction {
  type: "create_repair" | "create_apply";
  description: string;
  params: Record<string, unknown>;
}

interface ChatResult {
  intent: string;
  reply: string;
  needConfirmation: boolean;
  pendingAction: PendingAction | null;
}

const SYSTEM_PROMPT = `# 角色
你是一个IT资产管理系统的智能助手，名为"IT助手"。你帮助员工处理与办公设备相关的问题。

# 重要原则
1. 回复必须简洁、友好、有指导性，使用中文
2. 涉及创建工单、提交申领等实际操作时，必须先请求用户确认，不能直接执行
3. 用户询问资产价格或供应商信息时，回复"抱歉，该信息不在你的权限范围内"
4. 如果不确定用户的意图，主动引导用户说明具体情况

# 输入
你将收到 JSON 格式的输入：
{
  "history": [{ "role": "user"|"assistant", "content": "消息内容" }],
  "message": "用户当前消息",
  "userContext": {
    "assets": [{ "id": "...", "modelName": "...", "brandName": "...", "category": "...", "status": "...", "warrantyExpiry": "..." }],
    "pendingTickets": [{ "id": "...", "type": "...", "status": "...", "createdAt": "..." }]
  }
}

# 意图分类
- query_asset: 查询资产（触发词：我的设备、我有什么资产）
- query_warranty: 查询保修（触发词：保修、保修期、过保）
- query_ticket: 查询工单（触发词：工单、申请进度）
- guide_repair: 引导报修（触发词：报修、坏了、出问题）→ 需二次确认
- guide_apply: 引导申领（触发词：申领、申请、我要一台）→ 需二次确认
- fallback: 兜底（无法归类的其他消息）

# 输出格式

对于 query_asset / query_warranty / query_ticket（仅查询）：
{
  "intent": "query_asset",
  "reply": "自然语言回复",
  "needConfirmation": false,
  "pendingAction": null
}

对于 guide_repair / guide_apply（需要二次确认）：
{
  "intent": "guide_repair",
  "reply": "即将为你创建XXX，请确认是否继续？",
  "needConfirmation": true,
  "pendingAction": {
    "type": "create_repair" | "create_apply",
    "description": "具体操作描述",
    "params": { ... }
  }
}

对于 fallback：
{
  "intent": "fallback",
  "reply": "友好引导回复",
  "needConfirmation": false,
  "pendingAction": null
}`;

export async function POST(request: NextRequest) {
  try {
    const user = await verifyAuth(request);

    const body = (await request.json()) as ChatRequest;
    if (!body.message || typeof body.message !== "string") {
      return Response.json({ error: "message is required" }, { status: 400 });
    }

    // Fetch user context: assets and pending tickets
    const userAssets = await prisma.assetInstance.findMany({
      where: { holderId: user.userId },
      include: { model: true },
    });

    const pendingTickets = await prisma.ticket.findMany({
      where: {
        applicantId: user.userId,
        status: { notIn: ["COMPLETED", "CANCELLED", "REJECTED"] },
      },
      orderBy: { createdAt: "desc" },
      take: 10,
    });

    const userContext = {
      assets: userAssets.map((a) => ({
        id: a.id,
        modelName: a.model.modelName,
        brandName: a.model.brandName,
        category: a.model.category,
        status: a.status,
        warrantyExpiry: a.warrantyExpiry.toISOString(),
      })),
      pendingTickets: pendingTickets.map((t) => ({
        id: t.id,
        type: t.type,
        status: t.status,
        createdAt: t.createdAt.toISOString(),
      })),
    };

    const userPrompt = JSON.stringify({
      history: body.history ?? [],
      message: body.message,
      userContext,
    });

    const result = await withAiFallback(
      () =>
        callDeepSeek<ChatResult>({
          messages: [
            { role: "system", content: SYSTEM_PROMPT },
            { role: "user", content: userPrompt },
          ],
        }),
      "AI 助手暂时不可用，你可以通过「我的资产」查看资产信息，或通过「申领设备」/「报修」提交申请。",
    );

    if (!result.ok) {
      return Response.json(
        {
          reply: result.fallback,
          needConfirmation: false,
          pendingAction: null,
        },
        { status: 200 },
      );
    }

    const chatResult = result.data;

    // If confirmation is needed, generate a one-time token
    let confirmationToken: string | null = null;
    if (chatResult.needConfirmation && chatResult.pendingAction) {
      confirmationToken = await generateConfirmationToken({
        userId: user.userId,
        action: chatResult.pendingAction.type,
        params: chatResult.pendingAction.params,
      });
    }

    return Response.json(
      {
        reply: chatResult.reply,
        needConfirmation: chatResult.needConfirmation,
        pendingAction: chatResult.pendingAction,
        confirmationToken,
      },
      { status: 200 },
    );
  } catch (e) {
    if (e instanceof AuthError) {
      return Response.json({ error: e.message }, { status: e.statusCode });
    }
    return Response.json({ error: "Internal server error" }, { status: 500 });
  }
}
